import math

def rainbow_dqn_loss(
    online_V_logits, online_A_logits, target_V_logits, target_A_logits,
    actions, rewards, dones, gamma_n, v_min, v_max, n_atoms
):
    batch_size = len(actions)
    n_actions = len(online_A_logits[0])
    delta_z = (v_max - v_min) / (n_atoms - 1)
    support = [v_min + i * delta_z for i in range(n_atoms)]

    def softmax_1d(x):
        m = max(x)
        exp_x = [math.exp(xi - m) for xi in x]
        s = sum(exp_x)
        return [e / s for e in exp_x]

    # 1. Dueling combination: Q = V + A - mean(A) per atom
    online_Q_probs, target_Q_probs = [], []
    for b in range(batch_size):
        mean_A_on = [
            sum(online_A_logits[b][a][z] for a in range(n_actions)) / n_actions
            for z in range(n_atoms)
        ]
        mean_A_tg = [
            sum(target_A_logits[b][a][z] for a in range(n_actions)) / n_actions
            for z in range(n_atoms)
        ]
        online_Q_probs.append([
            softmax_1d([online_V_logits[b][z] + online_A_logits[b][a][z] - mean_A_on[z]
                        for z in range(n_atoms)])
            for a in range(n_actions)
        ])
        target_Q_probs.append([
            softmax_1d([target_V_logits[b][z] + target_A_logits[b][a][z] - mean_A_tg[z]
                        for z in range(n_atoms)])
            for a in range(n_actions)
        ])

    # 3. Double action selection: online network picks next action
    next_actions = []
    for b in range(batch_size):
        q_vals = [
            sum(online_Q_probs[b][a][z] * support[z] for z in range(n_atoms))
            for a in range(n_actions)
        ]
        next_actions.append(q_vals.index(max(q_vals)))

    # 4. Extract target distributions for selected next actions
    target_next_probs = [target_Q_probs[b][next_actions[b]] for b in range(batch_size)]

    # 5. Distributional Bellman projection
    m_all = [[0.0] * n_atoms for _ in range(batch_size)]
    for b in range(batch_size):
        for j in range(n_atoms):
            Tz_j = rewards[b] + (1 - dones[b]) * gamma_n * support[j]
            Tz_j = max(v_min, min(v_max, Tz_j))
            bj = (Tz_j - v_min) / delta_z
            l = max(0, min(n_atoms - 1, int(math.floor(bj))))
            u = max(0, min(n_atoms - 1, int(math.ceil(bj))))
            p_j = target_next_probs[b][j]
            if l == u:
                m_all[b][l] += p_j
            else:
                m_all[b][l] += p_j * (u - bj)
                m_all[b][u] += p_j * (bj - l)

    # 6. Cross-entropy loss between projected target and online distribution
    losses, priorities = [], []
    for b in range(batch_size):
        probs = online_Q_probs[b][actions[b]]
        loss = -sum(m_all[b][z] * math.log(probs[z] + 1e-8) for z in range(n_atoms))
        losses.append(loss)
        priorities.append(abs(loss) + 1e-6)

    return losses, priorities, next_actions
